import React from "react";
import styles from "./mega-menu-list.module.css";

const MegaMenuList: React.FC = () => {
  return (
    <div className={styles.mega_menu_list}>
      <div className={styles.divider} />
      <ul className={styles.list_container}>
        <li>
          <a href="/somepage" className={styles.list_link}>
          New season
          </a>
        </li>
        <li>
          <a href="/somepage" className={styles.list_link}>
            2
          </a>
        </li>
        <li>
          <a href="/somepage" className={styles.list_link}>
            3
          </a>
        </li>
      </ul>
    </div>
  );
};

export default MegaMenuList;
